    {"id": "GS057", "section": "General Science", "topic": "Atmosphere", "question_text": "The ozone layer, which protects Earth from UV radiation, is in the:", "options": ["Troposphere", "Stratosphere", "Mesosphere", "Thermosphere"], "correct_index": 1, "difficulty": 1, "explanation": "The ozone layer is in the stratosphere, approximately 15-35 km above Earth's surface. Ozone (O3) absorbs harmful UV radiation. The troposphere is below it, where we live and where weather happens.", "test_types": ["ASVAB"]},
    {"id": "GS058", "section": "General Science", "topic": "Atmosphere", "question_text": "Which layer of the atmosphere burns up most meteoroids before they reach Earth?", "options": ["Troposphere", "Stratosphere", "Mesosphere", "Exosphere"], "correct_index": 2, "difficulty": 2, "explanation": "The mesosphere (50-80 km altitude) is where most meteoroids burn up due to friction with air molecules, creating what we see as 'shooting stars.' The thermosphere is above it.", "test_types": ["ASVAB"]},

