    {"id": "GS059", "section": "General Science", "topic": "Rock Cycle", "question_text": "Igneous rocks form from:", "options": ["Layers of sediment compressed over time", "Melted rock (magma or lava) that has cooled", "Existing rocks changed by heat and pressure", "Shell fragments cemented together"], "correct_index": 1, "difficulty": 1, "explanation": "Igneous rocks form from cooled magma (underground) or lava (surface). Granite and basalt are igneous. Sedimentary rocks form from compressed sediment. Metamorphic rocks form from existing rocks under heat/pressure.", "test_types": ["ASVAB"]},
    {"id": "GS060", "section": "General Science", "topic": "Rock Cycle", "question_text": "Fossils are most commonly found in which type of rock?", "options": ["Igneous", "Metamorphic", "Sedimentary", "Volcanic"], "correct_index": 2, "difficulty": 1, "explanation": "Fossils form when organisms are buried in sediment that gradually compresses into sedimentary rock. The high heat and pressure involved in forming igneous and metamorphic rocks destroys most fossils.", "test_types": ["ASVAB"]},
    {"id": "GS061", "section": "General Science", "topic": "Rock Cycle", "question_text": "Metamorphic rocks are formed when existing rocks are subjected to:", "options": ["Erosion by wind and water", "Extreme heat and pressure", "Cooling of molten material", "Chemical reactions with acids"], "correct_index": 1, "difficulty": 2, "explanation": "Metamorphic rocks (marble, slate, schist) form when existing rocks are changed by extreme heat and/or pressure without melting. If the rock melted, it would become magma and form igneous rock instead.", "test_types": ["ASVAB"]},

    # === EARTH SCIENCE: Weather ===
    {"id": "GS062", "section": "General Science", "topic": "Weather", "question_text": "A cold front typically brings:", "options": ["Gradual warming and light rain", "Clear skies and high pressure", "Sudden storms and temperature drop", "Fog and drizzle"], "correct_index": 2, "difficulty": 2, "explanation": "Cold fronts bring sudden, severe weather — thunderstorms, heavy rain, and a rapid temperature drop as cold air pushes under warm air. Warm fronts bring gradual warming and steady rain.", "test_types": ["ASVAB"]},
    {"id": "GS063", "section": "General Science", "topic": "Weather", "question_text": "Low atmospheric pressure is generally associated with:", "options": ["Clear, calm weather", "Storm development", "Cold, dry air", "High winds only"], "correct_index": 1, "difficulty": 2, "explanation": "Low pressure areas have rising air, which leads to cloud formation and storms. High pressure areas have sinking air, associated with clear, calm weather. Meteorologists watch pressure to forecast storms.", "test_types": ["ASVAB"]},

    # === EARTH SCIENCE: Water Cycle ===
    {"id": "GS064", "section": "General Science", "topic": "Water Cycle", "question_text": "Water vapor turning into liquid water droplets when cooled is called:", "options": ["Evaporation", "Precipitation", "Condensation", "Transpiration"], "correct_index": 2, "difficulty": 1, "explanation": "Condensation is the process by which water vapor cools and changes to liquid water — it forms clouds and dew. Evaporation is the reverse (liquid to gas). Precipitation is water falling from clouds.", "test_types": ["ASVAB"]},
    {"id": "GS065", "section": "General Science", "topic": "Water Cycle", "question_text": "In the water cycle, the energy source that drives evaporation is:", "options": ["Wind", "Gravity", "Sunlight", "The moon's gravity"], "correct_index": 2, "difficulty": 1, "explanation": "Sunlight provides the energy (heat) that evaporates water from oceans, lakes, and other surfaces. Gravity drives precipitation (water falling) and surface runoff. Wind helps distribute moisture.", "test_types": ["ASVAB"]},

