    {"id": "GS067", "section": "General Science", "topic": "Solar System", "question_text": "Which planet is the largest in our solar system?", "options": ["Saturn", "Neptune", "Earth", "Jupiter"], "correct_index": 3, "difficulty": 1, "explanation": "Jupiter is the largest planet, with a mass more than twice that of all other planets combined. It is a gas giant and has a famous storm called the Great Red Spot.", "test_types": ["ASVAB"]},
